import{_ as a,o as c,c as o,a3 as r}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module generate:cache","description":"clore::generate::cache 模块负责为 LLM 生成的输出提供持久化缓存设施，以避免重复计算相同提示。其公共接口包括：缓存索引的类型 CacheIndex 与错误类型 CacheError；同步/异步加载缓存索引的函数 load_cache_index 与 load_cache_index_async；同步/异步保存缓存条目的函数 save_cache_entry 与 save_cache_entry_async；在已加载的索引中查找缓存响应的 find_cached_response；以及生成唯一缓存键的 make_prompt_response_cache_key 和规范化文本用于哈希的 normalize_text_for_hashing。该模块依赖 protocol、support 和标准库，内部通过批量的 JSONL 文件管理缓存条目，并支持基于事件循环的异步操作。","frontmatter":{"title":"Module generate:cache","description":"clore::generate::cache 模块负责为 LLM 生成的输出提供持久化缓存设施，以避免重复计算相同提示。其公共接口包括：缓存索引的类型 CacheIndex 与错误类型 CacheError；同步/异步加载缓存索引的函数 load_cache_index 与 load_cache_index_async；同步/异步保存缓存条目的函数 save_cache_entry 与 save_cache_entry_async；在已加载的索引中查找缓存响应的 find_cached_response；以及生成唯一缓存键的 make_prompt_response_cache_key 和规范化文本用于哈希的 normalize_text_for_hashing。该模块依赖 protocol、support 和标准库，内部通过批量的 JSONL 文件管理缓存条目，并支持基于事件循环的异步操作。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/generate/cache.md","filePath":"zh/clore/modules/generate/cache.md"}'),t={name:"zh/clore/modules/generate/cache.md"};function d(i,e,n,l,s,h){return c(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="module-generate-cache" tabindex="-1">Module <code>generate:cache</code> <a class="header-anchor" href="#module-generate-cache" aria-label="Permalink to &quot;Module `generate:cache`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::generate::cache</code> 模块负责为 LLM 生成的输出提供持久化缓存设施，以避免重复计算相同提示。其公共接口包括：缓存索引的类型 <code>CacheIndex</code> 与错误类型 <code>CacheError</code>；同步/异步加载缓存索引的函数 <code>load_cache_index</code> 与 <code>load_cache_index_async</code>；同步/异步保存缓存条目的函数 <code>save_cache_entry</code> 与 <code>save_cache_entry_async</code>；在已加载的索引中查找缓存响应的 <code>find_cached_response</code>；以及生成唯一缓存键的 <code>make_prompt_response_cache_key</code> 和规范化文本用于哈希的 <code>normalize_text_for_hashing</code>。该模块依赖 <code>protocol</code>、<code>support</code> 和标准库，内部通过批量的 JSONL 文件管理缓存条目，并支持基于事件循环的异步操作。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../protocol/"><code>protocol</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./scheduler"><code>generate:scheduler</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-generate-cache-cacheerror" tabindex="-1"><code>clore::generate::cache::CacheError</code> <a class="header-anchor" href="#clore-generate-cache-cacheerror" aria-label="Permalink to &quot;`clore::generate::cache::CacheError`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:16</code></p><p>Definition: <code>generate/cache.cppm:16</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p><code>clore::generate::cache::CacheError</code> 仅包含一个 <code>std::string message</code> 数据成员，没有其他状态或辅助函数。内部不变量要求 <code>message</code> 在构造后保持有效字符串（可为空），但未通过构造函数显式约束；直接暴露成员允许调用方任意赋值，因此不变量完全依赖使用方维护。该结构体未定义任何特殊成员函数，完全依赖编译器生成的默认构造函数、析构函数和拷贝/移动操作，作为轻量级错误传递类型使用。</p><h3 id="clore-generate-cache-cacheindex" tabindex="-1"><code>clore::generate::cache::CacheIndex</code> <a class="header-anchor" href="#clore-generate-cache-cacheindex" aria-label="Permalink to &quot;`clore::generate::cache::CacheIndex`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:20</code></p><p>Definition: <code>generate/cache.cppm:20</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p><code>clore::generate::cache::CacheIndex</code> 作为一个轻量数据结构实现，其底层存储完全由 <code>std::unordered_map&lt;std::string, std::string&gt; entries</code> 构成。该成员负责维护从键到值的映射关系，提供平均常数时间的插入、查找与删除操作。内部不变量要求 <code>entries</code> 中的键必须唯一且非空，但字符串内容不作格式限制。由于 <code>entries</code> 是公开字段，实现上不封装任何访问控制逻辑，调用方直接通过该成员管理缓存索引条目。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>entries</code> map contains string keys mapped to string values.</li><li>Keys are expected to be unique within the map.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>entries</code>: the underlying <code>std::unordered_map&lt;std::string, std::string&gt;</code> that holds the cache index data.</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to look up cached results by key.</li><li>Populated and queried by cache management functions.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-cache-find-cached-response" tabindex="-1"><code>clore::generate::cache::find_cached_response</code> <a class="header-anchor" href="#clore-generate-cache-find-cached-response" aria-label="Permalink to &quot;`clore::generate::cache::find_cached_response`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:35</code></p><p>Definition: <code>generate/cache.cppm:347</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>函数<code>clore::generate::cache::find_cached_response</code> 实现了基于内存哈希索引的查找算法。它接受一个<code>CacheIndex</code>类型引用和<code>std::string_view</code>类型的<code>cache_key</code>参数。内部控制流首先将<code>cache_key</code>隐式转换为<code>std::string</code>以匹配<code>CacheIndex::entries</code>的键类型，然后在<code>index.entries</code>（该字段是一个关联容器）上调用<code>find</code>操作。若迭代器<code>it</code>指向<code>entries.end()</code>，则返回<code>std::nullopt</code>；否则返回<code>it-&gt;second</code>即对应的缓存响应值。该函数唯一依赖是<code>CacheIndex::entries</code>容器，其性能由底层哈希表（通常为<code>std::unordered_map</code>）决定，平均查找时间为常数。它不涉及文件系统或异步操作，完全在内存中完成查找。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>index</code> of type <code>const CacheIndex&amp;</code></li><li>parameter <code>cache_key</code> of type <code>std::string_view</code></li><li>field <code>index.entries</code> (a map)</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to retrieve a previously cached generation response</li><li>used in conjunction with <code>save_cache_entry</code> or similar caching functions</li></ul><h3 id="clore-generate-cache-load-cache-index" tabindex="-1"><code>clore::generate::cache::load_cache_index</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:29</code></p><p>Definition: <code>generate/cache.cppm:252</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>函数 <code>clore::generate::cache::load_cache_index</code> 的实现首先调用内部函数 <code>all_jsonl_files</code> 扫描工作区根目录下的所有 JSONL 文件。若该步骤失败，直接返回 <code>CacheError</code>。对于每一个成功读取的文件，通过 <code>kota::codec::json::parse</code> 逐行解析 JSON 对象，仅提取 <code>key</code> 和 <code>resp</code> 字段的非空字符串值，并将其插入到 <code>CacheIndex::entries</code> 映射中。文件读取或解析失败的条目会被静默跳过，最终返回构建完成的 <code>CacheIndex</code> 实例。该函数依赖文件系统扫描、文本读取、JSON 解析以及 <code>CacheIndex</code> 与 <code>CacheError</code> 类型。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Reads multiple JSONL files from disk</li><li>Allocates memory for the <code>CacheIndex</code> object</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>workspace_root</code> parameter</li><li>JSONL files on disk</li><li>file content strings</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>the returned <code>CacheIndex</code> instance&#39;s entries map</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Loading cache index for lookup</li><li>Called before <code>find_cached_response</code></li></ul><h3 id="clore-generate-cache-load-cache-index-async" tabindex="-1"><code>clore::generate::cache::load_cache_index_async</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index-async" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index_async`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:38</code></p><p>Definition: <code>generate/cache.cppm:356</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>该函数将同步的 <code>clore::generate::cache::load_cache_index</code> 调用包装为异步协程。它通过 <code>kota::queue</code> 将同步逻辑调度到传入的 <code>kota::event_loop &amp;loop</code> 中执行，并等待队列任务完成。若队列任务本身失败（例如异常导致调度错误），则构造一个 <code>CacheError</code> 并调用 <code>co_await kota::fail</code> 传播错误；若任务成功但内部的 <code>load_cache_index</code> 返回了错误（即 <code>std::expected</code> 不含值），则将该 <code>CacheError</code> 原样转发。仅当两者均成功时，才将加载得到的 <code>CacheIndex</code> 通过 <code>co_return</code> 移出返回。</p><p>内部控制流完全由协程的 <code>co_await</code> 驱动，依赖 <code>load_cache_index</code> 完成文件扫描与索引构建，而 <code>kota::queue</code> 确保工作线程安全地执行同步操作，避免阻塞事件循环。由于 <code>load_cache_index</code> 本身可能因路径无效、文件解析错误等返回 <code>CacheError</code>，该函数仅负责传递或包装这些错误，不涉及索引内容的理解或修改。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Loads the cache index from the filesystem via a queued task on the event loop</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>workspace_root</code> parameter</li><li><code>loop</code> parameter</li><li>Cache index file (via <code>load_cache_index</code>)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to obtain the cache index asynchronously before cache lookups or modifications</li><li>Used in coroutine contexts that need to interact with the generation cache</li></ul><h3 id="clore-generate-cache-make-prompt-response-cache-key" tabindex="-1"><code>clore::generate::cache::make_prompt_response_cache_key</code> <a class="header-anchor" href="#clore-generate-cache-make-prompt-response-cache-key" aria-label="Permalink to &quot;`clore::generate::cache::make_prompt_response_cache_key`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:24</code></p><p>Definition: <code>generate/cache.cppm:219</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>函数首先通过 <code>response_format_fingerprint</code> 和 <code>tool_choice_fingerprint</code> 将 <code>request</code> 中的结构化配置（输出格式与工具选择）转换为紧凑指纹字符串，若指纹生成失败则提前返回错误。随后对 <code>request.prompt</code> 及 <code>system_prompt</code> 字符串调用 <code>normalize_text_for_hashing</code> 进行规范化，并借助 <code>llvm::xxh3_64bits</code> 分别计算两者的64位哈希值。最终将所有组件依次拼接为制表符分隔的字符串：<code>request_key</code>、两个哈希的十进制表示、响应格式指纹、工具选择指纹，并在末尾附加一个表示 <code>request.output_contract</code> 枚举值的字符。该函数依赖 <code>normalize_text_for_hashing</code> 进行文本归一化，依赖 <code>response_format_fingerprint</code> 与 <code>tool_choice_fingerprint</code> 两个匿名命名空间内的辅助函数完成配置的序列化，整个过程的错误仅来源于指纹生成步骤。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>request_key</code></li><li><code>system_prompt</code></li><li><code>request.prompt</code></li><li><code>request.response_format</code></li><li><code>request.tool_choice</code></li><li><code>request.output_contract</code></li><li><code>normalize_text_for_hashing</code></li><li><code>llvm::xxh3_64bits</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to generate a unique cache key for storing or retrieving cached responses</li><li>called by cache lookup and insertion functions</li></ul><h3 id="clore-generate-cache-normalize-text-for-hashing" tabindex="-1"><code>clore::generate::cache::normalize_text_for_hashing</code> <a class="header-anchor" href="#clore-generate-cache-normalize-text-for-hashing" aria-label="Permalink to &quot;`clore::generate::cache::normalize_text_for_hashing`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:192</code></p><p>Definition: <code>generate/cache.cppm:192</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>Implementation: <a href="./functions/normalize-text-for-hashing">Implementation</a></p><p>该函数通过两个阶段实现文本规范化。第一阶段从前向后扫描输入并跳过所有前导空白字符（使用 <code>std::isspace</code> 检查每个字符），因此只保留第一个非空白字符之后的文本。第二阶段从第一个非空白字符开始遍历剩余字符：遇到空白字符时，仅设置一个布尔标记 <code>prev_space</code>，不直接向结果追加空白；遇到非空白字符时，若 <code>prev_space</code> 为真且结果非空，则在追加该字符前先插入一个空格，然后重置标记。这一逻辑将任意长度的连续空白序列压缩为一个空格，同时确保结果字符串不会以空格开头（因为前导空白已跳过）且末尾不会有多余空格（只有当非空白字符之后有空白时才可能追加空格，而末尾空白序列永远不会触发追加）。整个过程完全基于标准库函数 <code>std::isspace</code> 和 <code>std::string</code> 的 <code>reserve</code>、<code>push_back</code>，无需其他外部依赖。</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>allocates a new string</li></ul><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>text</code> parameter</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>local variable <code>result</code></li><li>return value (new <code>std::string</code>)</li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>clore::generate::cache::make_prompt_response_cache_key</code> to normalize prompt or response text before hashing</li><li>used to ensure consistent cache keys regardless of whitespace variation</li></ul><h3 id="clore-generate-cache-save-cache-entry" tabindex="-1"><code>clore::generate::cache::save_cache_entry</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:31</code></p><p>Definition: <code>generate/cache.cppm:303</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>函数通过互斥锁 <code>cache_file_mutex</code> 序列化对缓存文件的并发写入，确保线程安全。内部流程首先调用 <code>cache_directory(workspace_root)</code> 获取缓存目录路径，若失败则返回 <code>CacheError</code>；成功后使用 <code>fs::create_directories</code> 确保目录存在，失败同样返回错误。接着由 <code>current_jsonl_filename()</code> 生成当前 JSONL 文件名，拼接出完整路径。调用 <code>build_jsonl_line(cache_key, response)</code> 构建单行记录，然后以二进制追加模式打开文件，写入该行并刷新缓冲区。任何打开或写入失败都返回描述性 <code>CacheError</code>。该函数依赖于 <code>cache_directory</code>、<code>build_jsonl_line</code> 和 <code>current_jsonl_filename</code> 三个辅助函数，所有错误均封装为 <code>CacheError</code> 结构体。</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>writes a JSONL line to the prompt response cache file</li><li>creates cache directories if they do not exist</li><li>acquires a static mutex for synchronization</li></ul><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>workspace_root</code></li><li>parameter <code>cache_key</code></li><li>parameter <code>response</code></li><li>result of <code>cache_directory(workspace_root)</code></li><li>result of <code>current_jsonl_filename()</code></li><li>result of <code>build_jsonl_line(cache_key, response)</code></li><li>static mutex <code>cache_file_mutex</code></li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>filesystem: creates directories under <code>workspace_root</code> cache path</li><li>filesystem: appends data to the JSONL cache file</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called after a successful generation to persist the response</li><li>synchronous version of <code>save_cache_entry_async</code></li><li>invoked by higher-level generation routines</li></ul><h3 id="clore-generate-cache-save-cache-entry-async" tabindex="-1"><code>clore::generate::cache::save_cache_entry_async</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry-async" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry_async`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:41</code></p><p>Definition: <code>generate/cache.cppm:376</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>函数 <code>clore::generate::cache::save_cache_entry_async</code> 是一个基于 <code>kota::task</code> 的异步协程，它将实际工作委托给同步版本 <code>save_cache_entry</code>。内部控制流先将参数转移至 <code>kota::queue</code> 调用中，该调用在给定的 <code>kota::event_loop</code> 上调度闭包，捕获 <code>workspace_root</code>、<code>cache_key</code> 和 <code>response</code> 并通过移动传入。<code>kota::queue</code> 返回 <code>queued_result</code>，如果该结果表示取消（通过 <code>catch_cancel</code>），则函数直接通过 <code>kota::fail</code> 返回一个 <code>CacheError</code>，其 <code>.message</code> 指示保存任务失败。否则检查 <code>queued_result</code> 是否持有 <code>std::expected</code>，若内部值无值（即同步 <code>save_cache_entry</code> 返回错误），则将该错误移动至 <code>kota::fail</code> 传播。成功时协程完成返回。主要依赖包括 <code>kota::event_loop</code>、<code>kota::queue</code>、<code>kota::fail</code>、<code>kota::task</code> 以及核心同步函数 <code>save_cache_entry</code>（位于同一命名空间）和 <code>CacheError</code> 结构体。</p><h4 id="side-effects-6" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-6" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Writes cache entry to disk via <code>save_cache_entry</code></li><li>Invokes asynchronous I/O through event loop</li></ul><h4 id="reads-from-6" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-6" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>workspace_root</code> string parameter</li><li><code>cache_key</code> string parameter</li><li><code>response</code> string parameter</li><li><code>loop</code> event loop parameter</li><li>Result of queued <code>save_cache_entry</code> call</li></ul><h4 id="writes-to-3" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-3" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Cache storage (disk) via <code>save_cache_entry</code></li><li>Coroutine state</li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to persist a generated response asynchronously</li><li>Used after response generation to avoid blocking the main thread</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>generate:cache</code> 模块实现了针对 LLM 响应结果的持久化缓存机制。它公开了 <code>load_cache_index</code> / <code>load_cache_index_async</code>、<code>save_cache_entry</code> / <code>save_cache_entry_async</code> 以及 <code>find_cached_response</code> 等同步与异步接口，并通过 <code>make_prompt_response_cache_key</code> 和内部文本规范化函数保证缓存键的唯一性与可再现性。模块采用基于 JSONL 文件的存储布局，缓存索引（<code>CacheIndex</code>）作为内存中的条目映射，避免每次查询时全量扫描磁盘。在实现结构上，它引入匿名命名空间封装了 <code>cache_directory</code>、<code>build_jsonl_line</code>、<code>format_iso_timestamp</code>、<code>tool_choice_fingerprint</code> 等文件路径组装、行构造与指纹生成逻辑，同时利用 <code>kota::event_loop</code> 将 I/O 操作委托给事件循环，实现非阻塞的文件加载与写入。</p><p>模块的依赖仅限于 <code>protocol</code>（LLM 请求/响应类型）和 <code>support</code>（UTF‑8 文本处理、文件读写、路径规范化等基础设施），自身不介入更上层的协议编排。内部分层清晰：基础层处理文件系统操作与文本格式化，中层管理索引加载与条目查找/保存，外层通过同步/异步函数向调用者提供统一接口。缓存键由提示、响应格式和工具选择等参数复合生成，写入时还结合时间戳与锁机制（<code>cache_file_mutex</code>）保护并发安全，形成一套完整且可独立测试的缓存子系统。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../support/">Module support</a></li></ul>',117)])])}const _=a(t,[["render",d]]);export{u as __pageData,_ as default};
